15	#ifndef SW_OPT_LITERT_MICRO_ACCUMULATOR_UTIL_H_
16	#define SW_OPT_LITERT_MICRO_ACCUMULATOR_UTIL_H_
17	
18	#include <riscv_vector.h>
19	
20	#include <algorithm>
21	#include <cstdint>
22	#include <limits>
23	
24	#include "tensorflow/lite/kernels/internal/common.h"
25	
26	#if TFLITE_SINGLE_ROUNDING
27	#error "TFLITE_SINGLE_ROUNDING is not supported"
28	#endif  // TFLITE_SINGLE_ROUNDING
