30	namespace coralnpu_v2::opt::litert_micro {
31	inline void PrepareShiftParams(uint8_t* left, uint8_t* right,
32	                               const int32_t* shift_in, int out_d) {
33	  int out_ch = 0;
34	  size_t out_ch_rem = out_d;
35	  while (out_ch_rem > 0) {
36	    const size_t vl = __riscv_vsetvl_e32m8(out_ch_rem);
37	    const vint32m8_t shift32 = __riscv_vle32_v_i32m8(&shift_in[out_ch], vl);
38	    const vint16m4_t shift16 = __riscv_vncvt_x_x_w_i16m4(shift32, vl);
39	    const vint8m2_t shift8 = __riscv_vncvt_x_x_w_i8m2(shift16, vl);
40	    const vint8m2_t neg = __riscv_vneg_v_i8m2(shift8, vl);
41	    // Positive values shift to LEFT, negative shift to right.
42	    const vuint8m2_t shl =
43	        __riscv_vreinterpret_v_i8m2_u8m2(__riscv_vmax_vx_i8m2(shift8, 0, vl));
44	    const vuint8m2_t shr =
45	        __riscv_vreinterpret_v_i8m2_u8m2(__riscv_vmax_vx_i8m2(neg, 0, vl));
46	    __riscv_vse8_v_u8m2(&left[out_ch], shl, vl);
47	    __riscv_vse8_v_u8m2(&right[out_ch], shr, vl);
48	    out_ch += vl;
49	    out_ch_rem -= vl;
50	  }
51	}
52	
53	// TODO(davidgao): use a param structure for reuse?
54	inline void PostprocessAcc(const int32_t* accs, const int32_t* bias_data,
55	                           const uint8_t* lshift, const int32_t* multiplier,
56	                           const uint8_t* rshift, int32_t out_offset,
57	                           int8_t out_min, int8_t out_max, int8_t* out_data,
58	                           int out_w, int out_d) {
59	  constexpr uint32_t vxrm = 0;  // round-to-nearest-up
60	
61	  int out_ch = 0;
62	  size_t out_ch_rem = out_d;
63	  while (out_ch_rem > 0) {
64	    const size_t vl = __riscv_vsetvl_e32m8(out_ch_rem);
65	    const vint32m8_t bias_val =
66	        bias_data ? __riscv_vle32_v_i32m8(&bias_data[out_ch], vl)
67	                  : __riscv_vmv_v_x_i32m8(0, vl);
68	    const vint32m8_t mul_val = __riscv_vle32_v_i32m8(&multiplier[out_ch], vl);
69	    const vuint8m2_t lsh8 = __riscv_vle8_v_u8m2(&lshift[out_ch], vl);
70	    const vuint8m2_t rsh8 = __riscv_vle8_v_u8m2(&rshift[out_ch], vl);
71	    const vuint32m8_t lsh32 = __riscv_vzext_vf4_u32m8(lsh8, vl);
72	    const vuint32m8_t rsh32 = __riscv_vzext_vf4_u32m8(rsh8, vl);
73	    for (int out_x = 0; out_x < out_w; ++out_x) {
74	      vint32m8_t acc = __riscv_vle32_v_i32m8(&accs[out_x * out_d + out_ch], vl);
75	      // Apply bias
76	      acc = __riscv_vadd_vv_i32m8(acc, bias_val, vl);
77	      // int8 uses left shift BEFORE multiplier
78	      acc = __riscv_vsll_vv_i32m8(acc, lsh32, vl);
79	      acc = __riscv_vsmul_vv_i32m8(acc, mul_val, vxrm, vl);
80	      // int8 uses rounding right shift
81	      acc = __riscv_vssra_vv_i32m8(acc, rsh32, vxrm, vl);
82	      // Apply offset
83	      acc = __riscv_vadd_vx_i32m8(acc, out_offset, vl);
84	      // Narrow down, saturating
85	      const vint16m4_t out16 = __riscv_vnclip_wx_i16m4(acc, 0, vxrm, vl);
86	      vint8m2_t out8 = __riscv_vnclip_wx_i8m2(out16, 0, vxrm, vl);
87	      // Apply clamping
88	      out8 = __riscv_vmax_vx_i8m2(out8, out_min, vl);
89	      out8 = __riscv_vmin_vx_i8m2(out8, out_max, vl);
90	      // Write out
91	      __riscv_vse8_v_i8m2(&out_data[out_x * out_d + out_ch], out8, vl);
92	    }
93	    out_ch += vl;
94	    out_ch_rem -= vl;
95	  }
96	}
97	
98	inline void PostprocessAcc16(const int32_t* accs, const int32_t* bias_data,
99	                             const uint8_t* lshift, const int32_t* multiplier,
100	                             const uint8_t* rshift, int32_t out_offset,
101	                             int16_t out_min, int16_t out_max,
102	                             int16_t* out_data, int out_w, int out_d) {
103	  // Scalar post-processing to ensure absolute bit-exactness with TFLM.
104	  // The user requested correctness over performance for this stage.
105	  for (int out_x = 0; out_x < out_w; ++out_x) {
106	    for (int c = 0; c < out_d; ++c) {
107	      int64_t acc = (int64_t)accs[out_x * out_d + c];
108	      if (bias_data) {
109	        acc += (int64_t)bias_data[c];
110	      }
111	
112	      int shift = (int8_t)lshift[c] - (int8_t)rshift[c];
113	      int32_t result =
114	          tflite::MultiplyByQuantizedMultiplier(acc, multiplier[c], shift);
115	
116	      result = std::max<int32_t>(result, out_min);
117	      result = std::min<int32_t>(result, out_max);
118	      out_data[out_x * out_d + c] = (int16_t)result;
119	    }
120	  }
121	}
122	}  // namespace coralnpu_v2::opt::litert_micro
123	
124	#endif  // SW_OPT_LITERT_MICRO_ACCUMULATOR_UTIL_H_
