15	#include "sw/opt/litert-micro/fully_connected.h"
16	
17	#include <riscv_vector.h>
18	
19	#include <algorithm>
20	#include <cstdint>
21	
22	#include "sw/opt/litert-micro/accumulator_util.h"
23	#include "tensorflow/lite/kernels/internal/reference/integer_ops/fully_connected.h"
24	#include "tensorflow/lite/kernels/internal/tensor_ctypes.h"
25	#include "tensorflow/lite/kernels/kernel_util.h"
26	#include "tensorflow/lite/micro/kernels/kernel_util.h"
27	
28	namespace coralnpu_v2::opt::litert_micro {
29	
30	void FullyConnected(
31	    const tflite::FullyConnectedParams& params,
32	    const tflite::RuntimeShape& input_shape, const int8_t* input_data,
33	    const tflite::RuntimeShape& filter_shape, const int8_t* filter_data,
34	    const tflite::RuntimeShape& bias_shape, const int32_t* bias_data,
35	    const tflite::RuntimeShape& output_shape, int8_t* output_data) {
36	  const int32_t input_offset = params.input_offset;
37	  const int32_t filter_offset = params.weights_offset;
38	  const int32_t output_offset = params.output_offset;
39	  const int32_t output_multiplier = params.output_multiplier;
40	  const int output_shift = params.output_shift;
41	  const int32_t output_activation_min = params.quantized_activation_min;
42	  const int32_t output_activation_max = params.quantized_activation_max;
43	
44	  const int batches =
45	      tflite::FlatSizeSkipDim(output_shape, output_shape.DimensionsCount() - 1);
46	  const int output_depth =
47	      output_shape.Dims(output_shape.DimensionsCount() - 1);
48	  const int accum_depth = filter_shape.Dims(filter_shape.DimensionsCount() - 1);
49	
50	  for (int b = 0; b < batches; ++b) {
51	    for (int out_c = 0; out_c < output_depth; ++out_c) {
52	      int d = 0;
53	      int d_rem = accum_depth;
54	
55	      // Use m4 for 32-bit accumulation to allow headroom
56	      vint32m4_t acc_v = __riscv_vmv_v_x_i32m4(0, __riscv_vsetvlmax_e32m4());
57	
58	      while (d_rem > 0) {
59	        size_t vl = __riscv_vsetvl_e8m1(d_rem);
60	        vint8m1_t in_v8 =
61	            __riscv_vle8_v_i8m1(&input_data[b * accum_depth + d], vl);
62	        vint8m1_t weight_v8 =
63	            __riscv_vle8_v_i8m1(&filter_data[out_c * accum_depth + d], vl);
64	
65	        // input + input_offset
66	        vint16m2_t in_v16 = __riscv_vadd_vx_i16m2(
67	            __riscv_vsext_vf2_i16m2(in_v8, vl), input_offset, vl);
68	        // weight + filter_offset
69	        vint16m2_t weight_v16 = __riscv_vadd_vx_i16m2(
70	            __riscv_vsext_vf2_i16m2(weight_v8, vl), filter_offset, vl);
71	
72	        // acc_v += (input + input_offset) * (weight + filter_offset)
73	        acc_v = __riscv_vwmacc_vv_i32m4(acc_v, in_v16, weight_v16, vl);
74	
75	        d += vl;
76	        d_rem -= vl;
77	      }
78	
79	      // Reduction
80	      vint32m1_t zero_v = __riscv_vmv_v_x_i32m1(0, 1);
81	      vint32m1_t sum_v = __riscv_vredsum_vs_i32m4_i32m1(
82	          acc_v, zero_v, __riscv_vsetvlmax_e32m4());
83	      int32_t acc = __riscv_vmv_x_s_i32m1_i32(sum_v);
84	
85	      if (bias_data) {
86	        acc += bias_data[out_c];
87	      }
88	
89	      int32_t acc_scaled = tflite::MultiplyByQuantizedMultiplier(
90	          acc, output_multiplier, output_shift);
91	      acc_scaled += output_offset;
92	      acc_scaled = std::max(acc_scaled, output_activation_min);
93	      acc_scaled = std::min(acc_scaled, output_activation_max);
94	      output_data[out_c + output_depth * b] = static_cast<int8_t>(acc_scaled);
95	    }
96	  }
97	}
98	
99	namespace {
100	TfLiteStatus FullyConnectedEval(TfLiteContext* context, TfLiteNode* node) {
101	  const auto& data =
102	      *(static_cast<const tflite::OpDataFullyConnected*>(node->user_data));
103	
104	  const TfLiteEvalTensor* input = tflite::micro::GetEvalInput(
105	      context, node, tflite::kFullyConnectedInputTensor);
106	  const TfLiteEvalTensor* filter = tflite::micro::GetEvalInput(
107	      context, node, tflite::kFullyConnectedWeightsTensor);
108	  const TfLiteEvalTensor* bias = tflite::micro::GetEvalInput(
109	      context, node, tflite::kFullyConnectedBiasTensor);
110	  TfLiteEvalTensor* output = tflite::micro::GetEvalOutput(
111	      context, node, tflite::kFullyConnectedOutputTensor);
112	
113	  if (input->type == kTfLiteInt8 && filter->type == kTfLiteInt8) {
114	    FullyConnected(tflite::FullyConnectedParamsQuantized(data),
115	                   tflite::micro::GetTensorShape(input),
116	                   tflite::micro::GetTensorData<int8_t>(input),
117	                   tflite::micro::GetTensorShape(filter),
118	                   tflite::micro::GetTensorData<int8_t>(filter),
119	                   tflite::micro::GetTensorShape(bias),
120	                   tflite::micro::GetOptionalTensorData<int32_t>(bias),
121	                   tflite::micro::GetTensorShape(output),
122	                   tflite::micro::GetTensorData<int8_t>(output));
123	    return kTfLiteOk;
124	  }
125	
126	  return tflite::Register_FULLY_CONNECTED().invoke(context, node);
127	}
128	}  // namespace
129	
130	TFLMRegistration Register_FULLY_CONNECTED() {
131	  auto registration = tflite::Register_FULLY_CONNECTED();
132	  registration.invoke = FullyConnectedEval;
133	  return registration;
134	}
135	
136	}  // namespace coralnpu_v2::opt::litert_micro
