43	  const int padding_height = params.padding_values.height;
44	  const int padding_width = params.padding_values.width;
45	  const int8_t activation_min = params.quantized_activation_min;
46	  const int8_t activation_max = params.quantized_activation_max;
47	
48	  for (int batch = 0; batch < batches; ++batch) {
49	    for (int out_y = 0; out_y < output_height; ++out_y) {
50	      for (int out_x = 0; out_x < output_width; ++out_x) {
51	        const int in_x_origin = (out_x * stride_width) - padding_width;
52	        const int in_y_origin = (out_y * stride_height) - padding_height;
53	        const int filter_x_start = std::max(0, -in_x_origin);
54	        const int filter_x_end =
55	            std::min(filter_width, input_width - in_x_origin);
56	        const int filter_y_start = std::max(0, -in_y_origin);
57	        const int filter_y_end =
58	            std::min(filter_height, input_height - in_y_origin);
59	
60	        int channel = 0;
61	        int channel_rem = depth;
62	        while (channel_rem > 0) {
63	          size_t vl = __riscv_vsetvl_e8m8(channel_rem);
64	          vint8m8_t max_v = __riscv_vmv_v_x_i8m8(-128, vl);
65	
66	          for (int filter_y = filter_y_start; filter_y < filter_y_end;
67	               ++filter_y) {
68	            for (int filter_x = filter_x_start; filter_x < filter_x_end;
69	                 ++filter_x) {
