71	              const int in_y = in_y_origin + filter_y;
72	              const int8_t* in_ptr =
73	                  input_data +
74	                  tflite::Offset(input_shape, batch, in_y, in_x, channel);
75	              vint8m8_t val_v = __riscv_vle8_v_i8m8(in_ptr, vl);
76	              max_v = __riscv_vmax_vv_i8m8(max_v, val_v, vl);
77	            }
78	          }
