#include "sw/opt/litert-micro/pooling.h"

#include <riscv_vector.h>

#include <algorithm>
#include <cstdint>

#include "tensorflow/lite/kernels/internal/reference/integer_ops/pooling.h"
#include "tensorflow/lite/kernels/internal/tensor_ctypes.h"
