29	#ifdef USE_TFLM_COMPRESSION
30	#error "USE_TFLM_COMPRESSION is not supported"
31	#endif  // USE_TFLM_COMPRESSION
32	
33	namespace coralnpu_v2::opt::litert_micro {
34	
35	using tflite::DepthwiseParams;
36	using tflite::kDepthwiseConvBiasTensor;
37	using tflite::kDepthwiseConvInputTensor;
38	using tflite::kDepthwiseConvOutputTensor;
39	using tflite::kDepthwiseConvWeightsTensor;
40	using tflite::NumInputs;
41	using tflite::OpDataConv;
42	using tflite::RuntimeShape;
43	using tflite::micro::GetEvalInput;
44	using tflite::micro::GetEvalOutput;
45	using tflite::micro::GetOptionalTensorData;
46	using tflite::micro::GetTensorData;
47	using tflite::micro::GetTensorShape;
48	
49	namespace {
50	// TODO(davidgao): move away?
51	inline int idiv_ceil(int x, int y) { return (x + y - 1) / y; }
52	
53	void DepthwiseConvPerChannelPatch(
54	    const DepthwiseParams& params, const int32_t* output_multiplier,
55	    const uint8_t* shift_left, const uint8_t* shift_right,
56	    const RuntimeShape& in_shape, const int8_t* in_data,
57	    const RuntimeShape& f_shape, const int8_t* f_data,
58	    const RuntimeShape& bias_shape, const int32_t* bias_data,
59	    const RuntimeShape& out_shape, int8_t* out_data, int out_y_st, int out_y_ed,
60	    int out_x_st, int out_x_ed, int32_t* accs) {
61	  // Get parameters.
62	  const int stride_w = params.stride_width;
63	  const int stride_h = params.stride_height;
64	  const int dilation_w = params.dilation_width_factor;
65	  const int dilation_h = params.dilation_height_factor;
66	  const int pad_w = params.padding_values.width;
67	  const int pad_h = params.padding_values.height;
68	  const int depth_multiplier = params.depth_multiplier;
69	  const int32_t output_offset = params.output_offset;
70	  const int8_t output_activation_min = params.quantized_activation_min;
71	  const int8_t output_activation_max = params.quantized_activation_max;
72	  const int16_t input_offset = params.input_offset;
73	
74	  TFLITE_DCHECK_LE(output_activation_min, output_activation_max);
75	  const int batches = MatchingDim(in_shape, 0, out_shape, 0);
76	  const int out_d = MatchingDim(f_shape, 3, out_shape, 3);
77	  const int in_h = in_shape.Dims(1);
78	  const int in_w = in_shape.Dims(2);
79	  const int in_d = in_shape.Dims(3);
80	  const int f_h = f_shape.Dims(1);
81	  const int f_w = f_shape.Dims(2);
82	
83	  for (int batch = 0; batch < batches; ++batch) {
84	    for (int out_y = out_y_st; out_y < out_y_ed; ++out_y) {
85	      const int in_y_orig = (out_y * stride_h) - pad_h;
86	      const int f_y_st = idiv_ceil(std::max(0, -in_y_orig), dilation_h);
87	      const int f_y_ed = std::min(f_h, idiv_ceil(in_h - in_y_orig, dilation_h));
88	      // Accumulators are at this scope.
89	      for (int out_x = out_x_st; out_x < out_x_ed; ++out_x) {
90	        const int in_x_orig = (out_x * stride_w) - pad_w;
91	        const int f_x_st = idiv_ceil(std::max(0, -in_x_orig), dilation_w);
92	        const int f_x_ed =
93	            std::min(f_w, idiv_ceil(in_w - in_x_orig, dilation_w));
94	        const int in_index_o2 =
95	            Offset(in_shape, batch, in_y_orig + dilation_h * f_y_st,
96	                   in_x_orig + dilation_w * f_x_st, 0);
97	        int in_ch = 0;
98	        size_t in_ch_rem = in_d;
99	        // TODO(davidgao): Consider moving this loop out. This could allow
100	        // systems with cache to reduce filter access cost.
101	        while (in_ch_rem > 0) {
102	          // Scalable with vlmax.
103	          const size_t vl = __riscv_vsetvl_e32m8(in_ch_rem);
104	          for (int m = 0; m < depth_multiplier; ++m) {
105	            const int out_ch = m + in_ch * depth_multiplier;
106	            // Initialize ACC
107	            vint32m8_t acc = __riscv_vmv_v_x_i32m8(0, vl);
108	            // This pair of ugly for loops are just doing scalar optimization
109	            // work for the compiler...
110	            for (int f_y = f_y_st, in_index_o1 = in_index_o2 + in_ch,
111	                     f_index_o1 = Offset(f_shape, 0, f_y_st, f_x_st, out_ch);
112	                 f_y < f_y_ed; ++f_y, in_index_o1 += dilation_h * in_w * in_d,
113	                     f_index_o1 += f_w * out_d) {
114	              for (int f_x = f_x_st, in_index_inner = in_index_o1,
115	                       f_index_inner = f_index_o1;
116	                   f_x < f_x_ed; ++f_x, in_index_inner += dilation_w * in_d,
117	                       f_index_inner += out_d) {
118	                const vint8m2_t in_val8 =
119	                    __riscv_vle8_v_i8m2(&in_data[in_index_inner], vl);
120	                const vint8m2_t f_val8 =
121	                    __riscv_vlse8_v_i8m2(&f_data[f_index_inner],
122	                                         sizeof(int8_t) * depth_multiplier, vl);
123	                vint16m4_t in_val16 = __riscv_vsext_vf2_i16m4(in_val8, vl);
124	                const vint16m4_t filter_val16 =
125	                    __riscv_vsext_vf2_i16m4(f_val8, vl);
126	                // Input offset is applied.
127	                // Ref kernel does not apply filter offset.
128	                in_val16 = __riscv_vadd_vx_i16m4(in_val16, input_offset, vl);
129	                // Multiply-accumulate
130	                acc = __riscv_vwmacc_vv_i32m8(acc, in_val16, filter_val16, vl);
131	              }
132	            }
133	            // Spill accumulators and postprocess later.
134	            __riscv_vsse32_v_i32m8(&accs[(out_x - out_x_st) * out_d + out_ch],
135	                                   sizeof(int32_t) * depth_multiplier, acc, vl);
136	          }
137	          in_ch += vl;
138	          in_ch_rem -= vl;
139	        }
140	      }
141	
142	      PostprocessAcc(accs, bias_data, shift_left, output_multiplier,
143	                     shift_right, output_offset, output_activation_min,
144	                     output_activation_max,
145	                     &out_data[Offset(out_shape, batch, out_y, out_x_st, 0)],
146	                     /*out_w=*/out_x_ed - out_x_st, /*out_d=*/out_d);
147	    }
148	  }
149	}
