151	void DepthwiseConvPerChannelPatchCenter3x3Reuse6(
152	    const DepthwiseParams& params, const int32_t* output_multiplier,
153	    const uint8_t* shift_left, const uint8_t* shift_right,
154	    const RuntimeShape& in_shape, const int8_t* in_data,
155	    const RuntimeShape& f_shape, const int8_t* f_data,
156	    const RuntimeShape& bias_shape, const int32_t* bias_data,
157	    const RuntimeShape& out_shape, int8_t* out_data, int out_y_st, int out_y_ed,
158	    int out_x_st, int out_x_ed, int32_t* accs) {
159	  // Get parameters.
160	  const int stride_w = params.stride_width;
161	  const int stride_h = params.stride_height;
162	  const int dilation_w = params.dilation_width_factor;
163	  const int dilation_h = params.dilation_height_factor;
164	  const int pad_w = params.padding_values.width;
165	  const int pad_h = params.padding_values.height;
166	  const int depth_multiplier = params.depth_multiplier;
167	  const int32_t output_offset = params.output_offset;
168	  const int8_t output_activation_min = params.quantized_activation_min;
169	  const int8_t output_activation_max = params.quantized_activation_max;
170	  const int16_t input_offset = params.input_offset;
171	
172	  TFLITE_DCHECK_LE(output_activation_min, output_activation_max);
173	  TFLITE_DCHECK_LE(stride_w, dilation_w);
174	
175	  const int batches = MatchingDim(in_shape, 0, out_shape, 0);
176	  const int out_d = MatchingDim(f_shape, 3, out_shape, 3);
177	  // const int in_h = in_shape.Dims(1);
178	  // const int in_w = in_shape.Dims(2);
179	  const int in_d = in_shape.Dims(3);
180	  // const int f_h = f_shape.Dims(1);
181	  // const int f_w = f_shape.Dims(2);
182	  const int out_patch_h = out_y_ed - out_y_st;
183	  const int out_patch_w = out_x_ed - out_x_st;
184	  const int32_t acc_shape_[] = {1, out_patch_h, out_patch_w, out_d};
185	  const tflite::RuntimeShape acc_shape(4, acc_shape_);
186	
187	  for (int batch = 0; batch < batches; ++batch) {
188	    // Accumulators in memory are at this scope.
189	    int in_ch = 0;
190	    size_t in_ch_rem = in_d;
191	    while (in_ch_rem > 0) {
192	      // Scalable with vlmax.
193	      const size_t vl = __riscv_vsetvl_e32m4(in_ch_rem);
194	      for (int m = 0; m < depth_multiplier; ++m) {
195	        const int out_ch = m + in_ch * depth_multiplier;
196	        // Load filter
197	        const vint8m1_t f00_v8 =
198	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 0, 0, out_ch)],
199	                                 sizeof(int8_t) * depth_multiplier, vl);
200	        const vint8m1_t f01_v8 =
201	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 0, 1, out_ch)],
202	                                 sizeof(int8_t) * depth_multiplier, vl);
203	        const vint8m1_t f02_v8 =
204	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 0, 2, out_ch)],
205	                                 sizeof(int8_t) * depth_multiplier, vl);
206	        const vint8m1_t f10_v8 =
207	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 1, 0, out_ch)],
208	                                 sizeof(int8_t) * depth_multiplier, vl);
209	        const vint8m1_t f11_v8 =
210	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 1, 1, out_ch)],
211	                                 sizeof(int8_t) * depth_multiplier, vl);
212	        const vint8m1_t f12_v8 =
213	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 1, 2, out_ch)],
214	                                 sizeof(int8_t) * depth_multiplier, vl);
215	        const vint8m1_t f20_v8 =
216	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 2, 0, out_ch)],
217	                                 sizeof(int8_t) * depth_multiplier, vl);
218	        const vint8m1_t f21_v8 =
219	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 2, 1, out_ch)],
220	                                 sizeof(int8_t) * depth_multiplier, vl);
221	        const vint8m1_t f22_v8 =
222	            __riscv_vlse8_v_i8m1(&f_data[Offset(f_shape, 0, 2, 2, out_ch)],
223	                                 sizeof(int8_t) * depth_multiplier, vl);
224	        for (int out_y = out_y_st; out_y < out_y_ed; ++out_y) {
225	          const int in_y_orig = (out_y * stride_h) - pad_h;
226	
227	          int out_x = out_x_st;
228	          int in_x_orig = (out_x * stride_w) - pad_w;
229	          vint8m1_t in00_v8 = __riscv_vle8_v_i8m1(
230	              &in_data[Offset(in_shape, batch, in_y_orig + 0 * dilation_h,
231	                              in_x_orig + 0 * dilation_w, in_ch)],
232	              vl);
233	          vint8m1_t in01_v8 = __riscv_vle8_v_i8m1(
234	              &in_data[Offset(in_shape, batch, in_y_orig + 0 * dilation_h,
235	                              in_x_orig + 1 * dilation_w, in_ch)],
236	              vl);
237	          vint8m1_t in10_v8 = __riscv_vle8_v_i8m1(
238	              &in_data[Offset(in_shape, batch, in_y_orig + 1 * dilation_h,
239	                              in_x_orig + 0 * dilation_w, in_ch)],
240	              vl);
241	          vint8m1_t in11_v8 = __riscv_vle8_v_i8m1(
242	              &in_data[Offset(in_shape, batch, in_y_orig + 1 * dilation_h,
243	                              in_x_orig + 1 * dilation_w, in_ch)],
244	              vl);
245	          vint8m1_t in20_v8 = __riscv_vle8_v_i8m1(
246	              &in_data[Offset(in_shape, batch, in_y_orig + 2 * dilation_h,
247	                              in_x_orig + 0 * dilation_w, in_ch)],
248	              vl);
249	          vint8m1_t in21_v8 = __riscv_vle8_v_i8m1(
250	              &in_data[Offset(in_shape, batch, in_y_orig + 2 * dilation_h,
251	                              in_x_orig + 1 * dilation_w, in_ch)],
252	              vl);
253	          const int8_t* in_ptr0 =
254	              &in_data[Offset(in_shape, batch, in_y_orig + 0 * dilation_h,
255	                              in_x_orig + 2 * dilation_w, in_ch)];
256	          const int8_t* in_ptr1 =
257	              &in_data[Offset(in_shape, batch, in_y_orig + 1 * dilation_h,
258	                              in_x_orig + 2 * dilation_w, in_ch)];
259	          const int8_t* in_ptr2 =
260	              &in_data[Offset(in_shape, batch, in_y_orig + 2 * dilation_h,
261	                              in_x_orig + 2 * dilation_w, in_ch)];
262	          while (out_x < out_x_ed) {
263	            // Initialize ACC
264	            vint32m4_t acc;
265	            // Fighting the compiler who wants to save a reg of 0s
266	            asm volatile(
267	                "vsetvli zero, %[vl], e32, m4, ta, ma;"
268	                "vmv.v.i %[acc], 0;"
269	                : [acc] "=vr"(acc)
270	                : [vl] "r"(vl)
271	                : "vl", "vtype");
272	            // Load and process input
273	            {
274	              // Row 0
275	              asm("vsetvli zero, %[vl], e16, m2, ta, ma;"
276	                  "vsext.vf2 v2, %[in0_v8];"
277	                  "vle8.v v1, %[in_ptr];"  // in2_v8
278	                  "vsext.vf2 v4, %[f0_v8];"
279	                  "vadd.vx v2, v2, %[in_offset];"
280	                  "vsext.vf2 v6, %[in1_v8];"  // Moved
281	                  "vwmacc.vv %[acc], v2, v4;"
282	                  "vadd.vx v6, v6, %[in_offset];"
283	                  "vsext.vf2 v4, %[f1_v8];"
284	                  "vsext.vf2 v2, v1;"  // Moved
285	                  "vwmacc.vv %[acc], v6, v4;"
286	                  "vadd.vx v2, v2, %[in_offset];"
287	                  "vsext.vf2 v4, %[f2_v8];"
288	                  "vmv1r.v %[in0_v8], %[in1_v8];"  // Moved
289	                  "vwmacc.vv %[acc], v2, v4;"
290	                  "vmv1r.v %[in1_v8], v1;"
291	                  : [acc] "+vr"(acc), [in0_v8] "+vr"(in00_v8),
292	                    [in1_v8] "+vr"(in01_v8)
293	                  : [f0_v8] "vr"(f00_v8), [f1_v8] "vr"(f01_v8),
294	                    [f2_v8] "vr"(f02_v8), [in_offset] "r"(input_offset),
295	                    [in_ptr] "A"(*in_ptr0), [vl] "r"(vl)
296	                  : "v1", "v2", "v3", "v4", "v5", "v6", "v7", "vl", "vtype");
297	            }
298	            {
299	              // Row 1
300	              asm("vsetvli zero, %[vl], e16, m2, ta, ma;"
301	                  "vsext.vf2 v2, %[in0_v8];"
302	                  "vle8.v v1, %[in_ptr];"  // in2_v8
303	                  "vsext.vf2 v4, %[f0_v8];"
304	                  "vadd.vx v2, v2, %[in_offset];"
305	                  "vsext.vf2 v6, %[in1_v8];"  // Moved
306	                  "vwmacc.vv %[acc], v2, v4;"
307	                  "vadd.vx v6, v6, %[in_offset];"
308	                  "vsext.vf2 v4, %[f1_v8];"
309	                  "vsext.vf2 v2, v1;"  // Moved
310	                  "vwmacc.vv %[acc], v6, v4;"
311	                  "vadd.vx v2, v2, %[in_offset];"
312	                  "vsext.vf2 v4, %[f2_v8];"
313	                  "vmv1r.v %[in0_v8], %[in1_v8];"  // Moved
314	                  "vwmacc.vv %[acc], v2, v4;"
315	                  "vmv1r.v %[in1_v8], v1;"
316	                  : [acc] "+vr"(acc), [in0_v8] "+vr"(in10_v8),
317	                    [in1_v8] "+vr"(in11_v8)
318	                  : [f0_v8] "vr"(f10_v8), [f1_v8] "vr"(f11_v8),
319	                    [f2_v8] "vr"(f12_v8), [in_offset] "r"(input_offset),
320	                    [in_ptr] "A"(*in_ptr1), [vl] "r"(vl)
321	                  : "v1", "v2", "v3", "v4", "v5", "v6", "v7", "vl", "vtype");
322	            }
323	            {
324	              // Row 2
325	              asm("vsetvli zero, %[vl], e16, m2, ta, ma;"
326	                  "vsext.vf2 v2, %[in0_v8];"
327	                  "vle8.v v1, %[in_ptr];"  // in2_v8
328	                  "vsext.vf2 v4, %[f0_v8];"
329	                  "vadd.vx v2, v2, %[in_offset];"
330	                  "vsext.vf2 v6, %[in1_v8];"  // Moved
331	                  "vwmacc.vv %[acc], v2, v4;"
332	                  "vadd.vx v6, v6, %[in_offset];"
333	                  "vsext.vf2 v4, %[f1_v8];"
334	                  "vsext.vf2 v2, v1;"  // Moved
335	                  "vwmacc.vv %[acc], v6, v4;"
336	                  "vadd.vx v2, v2, %[in_offset];"
337	                  "vsext.vf2 v4, %[f2_v8];"
338	                  "vmv1r.v %[in0_v8], %[in1_v8];"  // Moved
339	                  "vwmacc.vv %[acc], v2, v4;"
340	                  "vmv1r.v %[in1_v8], v1;"
341	                  : [acc] "+vr"(acc), [in0_v8] "+vr"(in20_v8),
342	                    [in1_v8] "+vr"(in21_v8)
343	                  : [f0_v8] "vr"(f20_v8), [f1_v8] "vr"(f21_v8),
344	                    [f2_v8] "vr"(f22_v8), [in_offset] "r"(input_offset),
345	                    [in_ptr] "A"(*in_ptr2), [vl] "r"(vl)
346	                  : "v1", "v2", "v3", "v4", "v5", "v6", "v7", "vl", "vtype");
347	            }
348	            // Spill accumulators and postprocess later.
349	            __riscv_vsse32_v_i32m4(&accs[Offset(acc_shape, 0, out_y - out_y_st,
350	                                                out_x - out_x_st, out_ch)],
351	                                   sizeof(int32_t) * depth_multiplier, acc, vl);
352	            // End of iteration
353	            ++out_x;
354	            in_x_orig += stride_w;
355	            in_ptr0 += stride_w * in_d;
356	            in_ptr1 += stride_w * in_d;
357	            in_ptr2 += stride_w * in_d;
358	          }
359	        }
360	      }
361	      in_ch += vl;
362	      in_ch_rem -= vl;
363	    }
364	
365	    for (int out_y = out_y_st; out_y < out_y_ed; ++out_y) {
366	      PostprocessAcc(&accs[Offset(acc_shape, 0, out_y - out_y_st, 0, 0)],
367	                     bias_data, shift_left, output_multiplier, shift_right,
368	                     output_offset, output_activation_min,
369	                     output_activation_max,
370	                     &out_data[Offset(out_shape, batch, out_y, out_x_st, 0)],
371	                     /*out_w=*/out_patch_w, /*out_d=*/out_d);
372	    }
373	  }
374	}
