377	void DepthwiseConvPerChannel(
378	    const DepthwiseParams& params, const int32_t* output_multiplier,
379	    const int32_t* output_shift, const RuntimeShape& in_shape,
380	    const int8_t* in_data, const RuntimeShape& f_shape, const int8_t* f_data,
381	    const RuntimeShape& bias_shape, const int32_t* bias_data,
382	    const RuntimeShape& out_shape, int8_t* out_data, int32_t* accs_buf) {
383	  // Check dimensions of the tensors.
384	  TFLITE_DCHECK_EQ(in_shape.DimensionsCount(), 4);
385	  TFLITE_DCHECK_EQ(f_shape.DimensionsCount(), 4);
386	  TFLITE_DCHECK_EQ(out_shape.DimensionsCount(), 4);
387	
388	  const int stride_w = params.stride_width;
389	  const int stride_h = params.stride_height;
390	  const int dilation_w = params.dilation_width_factor;
391	  const int dilation_h = params.dilation_height_factor;
392	  const int pad_w = params.padding_values.width;
393	  const int pad_h = params.padding_values.height;
394	  const int depth_multiplier = params.depth_multiplier;
395	
396	  const int out_h = out_shape.Dims(1);
397	  const int out_w = out_shape.Dims(2);
398	  const int out_d = MatchingDim(f_shape, 3, out_shape, 3);
399	  const int in_d = in_shape.Dims(3);
400	  const int f_h = f_shape.Dims(1);
401	  const int f_w = f_shape.Dims(2);
402	
403	  TFLITE_DCHECK_EQ(out_d, in_d * depth_multiplier);
404	  TFLITE_DCHECK_EQ(bias_shape.FlatSize(), out_d);
405	
406	  // Copy filter and bias to dtcm.
407	  // Copy filter and bias to dtcm.
408	  auto f_data_copy = make_aligned_array<int8_t>(16, f_shape.FlatSize(), f_data);
409	  // TODO(davidgao): if allocation fails, don't copy, use orig
410	  TFLITE_DCHECK_NE(f_data_copy, nullptr);
411	
412	  aligned_array<int32_t> bias_data_copy;
413	  if (bias_data) {
414	    bias_data_copy = make_aligned_array<int32_t>(16, out_d, bias_data);
415	    // TODO(davidgao): if allocation fails, don't copy, use orig
416	    TFLITE_DCHECK_NE(bias_data_copy, nullptr);
417	  }
418	
419	  // Shifting from quantization params.
420	  auto shift_left = make_aligned_array<uint8_t>(16, out_d);
421	  TFLITE_DCHECK_NE(shift_left, nullptr);
422	  auto shift_right = make_aligned_array<uint8_t>(16, out_d);
423	  TFLITE_DCHECK_NE(shift_right, nullptr);
424	  PrepareShiftParams(shift_left.get(), shift_right.get(), output_shift, out_d);
425	
426	  // Cut down into sections
427	  const int out_y_top = idiv_ceil(pad_h, stride_h);
428	  const int out_y_bottom =
429	      idiv_ceil(out_h + pad_h - f_h * dilation_h, stride_h);
430	  const int out_x_left = idiv_ceil(pad_w, stride_w);
431	  const int out_x_right = idiv_ceil(out_w + pad_w - f_w * dilation_w, stride_w);
432	
433	  // Top
434	  DepthwiseConvPerChannelPatch(
435	      params, output_multiplier, shift_left.get(), shift_right.get(), in_shape,
436	      in_data, f_shape, f_data_copy.get(), bias_shape, bias_data_copy.get(),
437	      out_shape, out_data, 0, out_y_top, 0, out_w, accs_buf);
438	  // Middle-left
439	  DepthwiseConvPerChannelPatch(
440	      params, output_multiplier, shift_left.get(), shift_right.get(), in_shape,
441	      in_data, f_shape, f_data_copy.get(), bias_shape, bias_data_copy.get(),
442	      out_shape, out_data, out_y_top, out_y_bottom, 0, out_x_left, accs_buf);
443	  // Center
444	  do {
445	    if ((f_h == 3) && (f_w == 3)) {
446	      if (stride_w == dilation_w) {
447	        DepthwiseConvPerChannelPatchCenter3x3Reuse6(
448	            params, output_multiplier, shift_left.get(), shift_right.get(),
449	            in_shape, in_data, f_shape, f_data_copy.get(), bias_shape,
450	            bias_data_copy.get(), out_shape, out_data, out_y_top, out_y_bottom,
451	            out_x_left, out_x_right, accs_buf);
452	        break;
453	      }
454	      // More variations to be added here
455	    }
456	    DepthwiseConvPerChannelPatch(
457	        params, output_multiplier, shift_left.get(), shift_right.get(),
458	        in_shape, in_data, f_shape, f_data_copy.get(), bias_shape,
459	        bias_data_copy.get(), out_shape, out_data, out_y_top, out_y_bottom,
460	        out_x_left, out_x_right, accs_buf);
461	  } while (false);
462	  // Middle-right
463	  DepthwiseConvPerChannelPatch(
464	      params, output_multiplier, shift_left.get(), shift_right.get(), in_shape,
465	      in_data, f_shape, f_data_copy.get(), bias_shape, bias_data_copy.get(),
466	      out_shape, out_data, out_y_top, out_y_bottom, out_x_right, out_w, accs_buf);
467	  // Bottom
468	  DepthwiseConvPerChannelPatch(
469	      params, output_multiplier, shift_left.get(), shift_right.get(), in_shape,
470	      in_data, f_shape, f_data_copy.get(), bias_shape, bias_data_copy.get(),
471	      out_shape, out_data, out_y_bottom, out_h, 0, out_w, accs_buf);
472	}
