479	TfLiteStatus DepthwiseConvPrepare(TfLiteContext* context, TfLiteNode* node) {
480	  TF_LITE_ENSURE_OK(context, tflite::DepthwiseConvPrepare(context, node));
481	
482	  OpDataConvCustom* data = static_cast<OpDataConvCustom*>(node->user_data);
483	  tflite::MicroContext* micro_context = tflite::GetMicroContext(context);
484	  TfLiteTensor* output =
485	      micro_context->AllocateTempOutputTensor(node, kDepthwiseConvOutputTensor);
486	  TF_LITE_ENSURE(context, output != nullptr);
487	
488	  const int batches = output->dims->data[0];
489	  const int output_height = output->dims->data[1];
490	  const int output_width = output->dims->data[2];
491	  const int output_depth = output->dims->data[3];
492	
493	  size_t required_bytes =
494	      batches * output_height * output_width * output_depth * sizeof(int32_t);
495	
496	  TF_LITE_ENSURE_STATUS(context->RequestScratchBufferInArena(
497	      context, required_bytes, &data->accs_buffer_index));
498	
499	  micro_context->DeallocateTempTfLiteTensor(output);
500	
501	  return kTfLiteOk;
502	}
