504	TfLiteStatus DepthwiseConvEval(TfLiteContext* context, TfLiteNode* node) {
505	  TFLITE_DCHECK(node->user_data != nullptr);
506	  TFLITE_DCHECK(node->builtin_data != nullptr);
507	
508	  const auto& params =
509	      *(reinterpret_cast<TfLiteDepthwiseConvParams*>(node->builtin_data));
510	  const auto& data = *(static_cast<const OpDataConvCustom*>(node->user_data));
511	
512	  int32_t* accs_buf = static_cast<int32_t*>(
513	      context->GetScratchBuffer(context, data.accs_buffer_index));
514	  TFLITE_DCHECK_NE(accs_buf, nullptr);
515	
516	  TfLiteEvalTensor* output =
517	      GetEvalOutput(context, node, kDepthwiseConvOutputTensor);
518	  const TfLiteEvalTensor* input =
519	      GetEvalInput(context, node, kDepthwiseConvInputTensor);
520	  const TfLiteEvalTensor* filter =
521	      GetEvalInput(context, node, kDepthwiseConvWeightsTensor);
522	  const TfLiteEvalTensor* bias =
523	      (NumInputs(node) == 3)
524	          ? GetEvalInput(context, node, kDepthwiseConvBiasTensor)
525	          : nullptr;
526	
527	  switch (input->type) {  // Already know in/out types are same.
528	    case kTfLiteInt8: {
529	      switch (filter->type) {
530	        case kTfLiteInt8: {
531	          DepthwiseConvPerChannel(
532	              DepthwiseConvParamsQuantized(params, data),
533	              data.per_channel_output_multiplier, data.per_channel_output_shift,
534	              GetTensorShape(input), GetTensorData<int8_t>(input),
535	              GetTensorShape(filter), GetTensorData<int8_t>(filter),
536	              GetTensorShape(bias), GetOptionalTensorData<int32_t>(bias),
537	              GetTensorShape(output), GetTensorData<int8_t>(output), accs_buf);
538	          break;
539	        }
540	        default:
541	          return tflite::Register_DEPTHWISE_CONV_2D().invoke(context, node);
542	      }
543	      break;
544	    }
545	    default:
546	      return tflite::Register_DEPTHWISE_CONV_2D().invoke(context, node);
547	  }
548	  return kTfLiteOk;
549	}
