551	TFLMRegistration Register_DEPTHWISE_CONV_2D() {
552	  auto registration = tflite::Register_DEPTHWISE_CONV_2D();
553	  registration.init = DepthwiseConvInit;
554	  registration.prepare = DepthwiseConvPrepare;
555	  registration.invoke = DepthwiseConvEval;
556	  return registration;
557	}
