            register vint32m4_t mul_acc2 __asm__("v24");
            mul_acc1 = __riscv_vmv_v_x_i32m4(0, 16);
            mul_acc2 = __riscv_vmv_v_x_i32m4(0, 16);

            if (in_y_origin >= 0 && in_y_origin + 3 < input_height &&
                in_x_origin1 >= 0 && in_x_origin2 + 3 < input_width) {
