    const int in_x_origin1 = ((out_x + 1) * stride_width) - pad_width;
    const int in_x_origin2 = ((out_x + 2) * stride_width) - pad_width;
    const int in_x_origin3 = ((out_x + 3) * stride_width) - pad_width;

